import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE_URL = "http://localhost:5000/api";

const PortForm = () => {
  const [name, setName] = useState("");
  const [port, setPort] = useState("");
  const [ports, setPorts] = useState([]);
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const resetForm = () => {
    setName("");
    setPort("");
    setEditingId(null);
  };

  const fetchData = async () => {
    const [portsRes, historyRes, statsRes] = await Promise.all([
      axios.get(`${API_BASE_URL}/all`),
      axios.get(`${API_BASE_URL}/history`),
      axios.get(`${API_BASE_URL}/history/stats`),
    ]);

    setPorts(portsRes.data);
    setHistory(historyRes.data);
    setStats(statsRes.data);
  };

  useEffect(() => {
    fetchData().catch(() => {
      setError("Unable to connect backend. Start server on port 5000.");
    });
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!name.trim() || !port) {
      setError("Please enter both port name and port number.");
      return;
    }

    try {
      setLoading(true);
      setError("");
      setSuccess("");

      if (editingId) {
        await axios.put(`${API_BASE_URL}/${editingId}`, { name, port });
        setSuccess("Port updated successfully.");
      } else {
        await axios.post(`${API_BASE_URL}/add`, { name, port });
        setSuccess("Port added successfully.");
      }

      resetForm();
      await fetchData();
    } catch (err) {
      const message = err?.response?.data?.error || "Request failed.";
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (item) => {
    setEditingId(item._id);
    setName(item.name);
    setPort(String(item.port));
    setError("");
    setSuccess("");
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      setError("");
      setSuccess("");
      await axios.delete(`${API_BASE_URL}/${id}`);
      setSuccess("Port deleted successfully.");
      await fetchData();
    } catch (err) {
      const message = err?.response?.data?.error || "Delete failed.";
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto mt-10 p-5 bg-white shadow-xl rounded-2xl">
      <h2 className="text-2xl font-bold mb-4 text-center">Manage Ports</h2>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-2">
        <input
          type="text"
          placeholder="Port name (e.g. HTTP)"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="p-2 border rounded-lg"
        />
        <input
          type="number"
          placeholder="Port number"
          value={port}
          onChange={(e) => setPort(e.target.value)}
          className="p-2 border rounded-lg"
        />
        <button type="submit" className="bg-blue-500 text-white px-4 rounded-lg">
          {loading ? "Saving..." : editingId ? "Update" : "Add"}
        </button>
      </form>

      {editingId && (
        <button
          type="button"
          onClick={resetForm}
          className="mt-3 px-4 py-2 text-sm bg-gray-200 rounded-lg"
        >
          Cancel Edit
        </button>
      )}

      {error && <p className="text-red-500 mt-2 text-center">{error}</p>}
      {success && <p className="text-green-600 mt-2 text-center">{success}</p>}

      <h3 className="mt-6 text-lg font-semibold">Saved Ports</h3>
      <div className="mt-3 space-y-3">
        {ports.map((item) => (
          <div
            key={item._id}
            className="flex justify-between items-center bg-gray-100 p-3 rounded-lg shadow"
          >
            <div>
              <p className="font-semibold text-gray-800">{item.name}</p>
              <p className="text-sm text-gray-500">Port: {item.port}</p>
            </div>
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => handleEdit(item)}
                className="bg-yellow-500 text-white px-3 py-1 rounded-lg"
              >
                Edit
              </button>
              <button
                type="button"
                onClick={() => handleDelete(item._id)}
                className="bg-red-500 text-white px-3 py-1 rounded-lg"
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>

      <h3 className="mt-8 text-lg font-semibold">Most Used Ports</h3>
      <div className="mt-3 space-y-2 text-left">
        {stats.length === 0 && (
          <p className="text-sm text-gray-500">No usage data available yet.</p>
        )}
        {stats.map((item) => (
          <div key={item.port} className="bg-blue-50 p-3 rounded-lg">
            <p className="font-medium">Port {item.port}</p>
            <p className="text-sm text-gray-600">Used {item.count} times</p>
          </div>
        ))}
      </div>

      <h3 className="mt-8 text-lg font-semibold">History</h3>
      <div className="mt-3 space-y-2 text-left">
        {history.length === 0 && <p className="text-sm text-gray-500">No history yet.</p>}
        {history.map((entry) => (
          <div key={entry._id} className="bg-gray-50 p-3 rounded-lg">
            <p className="text-sm font-medium">
              {entry.action.toUpperCase()} - {entry.name} (Port {entry.port})
            </p>
            <p className="text-xs text-gray-500">{new Date(entry.createdAt).toLocaleString()}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PortForm;
